import React, { useEffect } from "react";
import ReactDOM from "react-dom";
import { CSSTransition } from "react-transition-group";
import "./Modal.css";

const initialFormData = Object.freeze({
  title: "",
  category: "",
  shortDescription: "",
  fullDescription: "",
  city: "",
  state: "",
  country: "",
  locaton: "",
  hostMessage: "",
  nightlyFee: "",
  cleaningFee: "",
  serviceFee: "",
  guests: "",
  beds: "",
  baths: "",
  amenities: "",
  houseRumes: [],
  healthAndSafety: [],
  cancellationPolicy: [],
});

const Modal = (props) => {
  const [formData, updateFormData] = React.useState(initialFormData);
  const closeOnEscapeKeyDown = (e) => {
    if ((e.charCode || e.keyCode) === 27) {
      props.onClose();
    }
  };

  useEffect(() => {
    document.body.addEventListener("keydown", closeOnEscapeKeyDown);
    return function cleanup() {
      document.body.removeEventListener("keydown", closeOnEscapeKeyDown);
    };
  }, []);

  const handleChange = (e) => {
    updateFormData({
      ...formData,
      [e.target.name]: e.target.value.trim()
    });
  };

  return ReactDOM.createPortal(
    <CSSTransition
      in={props.show}
      unmountOnExit
      timeout={{ enter: 0, exit: 300 }}
    >
      <div className="modal" onClick={props.onClose}>
        <div className="modal-content" onClick={(e) => e.stopPropagation()}>
          <div className="modal-header">
            <h4 className="modal-title">{props.title}</h4>
          </div>
          <div className="modal-body">
            {props.children}
            Ankit
            <div className="card text-center" style={{ width: "100%" }}>
              <div className="card-body">
                <h5 className="card-title">Register for host</h5>
                <form>
                <div className="card text-center" style={{ marginTop: '10%', marginLeft: '35%', marginRight: '35%' }}>
        <div className="card-body">
          <h5 className="card-title">Sign up</h5>

          <div className="form-outline mb-4">
            <input name = "firstname" type="text" id="form2Example1" className="form-control"  onChange={handleChange} />
            {/* <label className="form-label" htmlFor="form2Example1">First Name</label> */}
            First Name
          </div>
          <div className="form-outline mb-4">
            <input name = "lastname" type="text" id="form2Example1" className="form-control"  onChange={handleChange} />
            {/* <label className="form-label" htmlFor="form2Example1">Last Name</label> */}
            Last Name
          </div>
          <div className="form-outline mb-4">
            <input name = "email" type="email" id="form2Example1" className="form-control"  onChange={handleChange} />
            {/* <label className="form-label" htmlFor="form2Example1">Email address</label> */}
            Email
          </div>

          {/* Password input */}
          <div className="form-outline mb-4">
            <input name = "password" type="password" id="form2Example2" className="form-control"  onChange={handleChange}/>
            {/* <label className="form-label" htmlFor="form2Example2">Password</label> */}
            Password
          </div>
          <div className="form-outline mb-4">
            <input name = "contact" type="text" id="form2Example1" className="form-control"  onChange={handleChange} />
            {/* <label className="form-label" htmlFor="form2Example1">Contact</label> */}
            Contact
          </div>
          <div className="form-outline mb-4">
            <input name = "dob" type="text" id="form2Example1" className="form-control"  onChange={handleChange} />
            {/* <label className="form-label" htmlFor="form2Example1">Date of birth</label> */}
            Date of Birth
          </div>
          <button type="button" className="btn btn-primary btn-block mb-4" onClick={handleSubmit}>Submit</button>
        </div>
      </div>
                  <button
                    type="button"
                    className="btn btn-primary btn-block mb-4"
                  >
                    Add
                  </button>
                </form>
              </div>
            </div>
          </div>
          <div className="modal-footer">
            <button onClick={props.onClose} className="button">
              Close
            </button>
          </div>
        </div>
      </div>
    </CSSTransition>,
    document.getElementById("root")
  );
};

export default Modal;
